UPDATE sg_strategy_snapshot
SET last_simulated_revenue_cny = #{row.lastSimulatedRevenueCny},
    confidence_low_cny         = #{row.confidenceLowCny},
    confidence_high_cny        = #{row.confidenceHighCny},
    success_probability_pct    = #{row.successProbabilityPct}
WHERE strategy_id = #{row.strategyId}

UPDATE sg_strategy
SET status     = #{status},
    updated_at = #{updatedAt}
WHERE id = #{id}
